exercises.solution_code:
def skip_reason(env):
    # 1. No network -> skip. A missing "online" key counts as offline.
    if not env.get("online", False):
        return "requires network"
    # 2. posix-only tests cannot run on Windows.
    if env.get("platform") == "windows" and env.get("posix_only", False):
        return "posix only"
    # 3. Nothing to skip for -> run the test.
    return None

tests.content:
import pytest

from solution import skip_reason


def test_offline_is_skipped():
    assert skip_reason({"online": False, "platform": "linux"}) == "requires network"


def test_online_posix_only_on_windows_is_skipped():
    env = {"online": True, "platform": "windows", "posix_only": True}
    assert skip_reason(env) == "posix only"


def test_online_normal_runs():
    env = {"online": True, "platform": "linux"}
    assert skip_reason(env) is None


def test_missing_online_key_treated_as_offline():
    # Edge: a missing "online" key means we cannot reach the network -> skip.
    assert skip_reason({"platform": "linux"}) == "requires network"


def test_offline_beats_posix_rule():
    # Tricky: offline is checked first, so its reason wins even when the
    # posix_only-on-windows condition is also true.
    env = {"online": False, "platform": "windows", "posix_only": True}
    assert skip_reason(env) == "requires network"


def test_posix_only_on_non_windows_runs():
    # Edge: posix_only is irrelevant unless the platform is windows.
    env = {"online": True, "platform": "linux", "posix_only": True}
    assert skip_reason(env) is None


@pytest.mark.parametrize("plat", ["linux", "darwin"])
def test_returns_none_not_false(plat):
    # Tricky: a non-skip must be exactly None, not False/"" -- callers
    # distinguish "no reason" (None) from a real reason string.
    result = skip_reason({"online": True, "platform": plat})
    assert result is None

