exercises.solution_code:
def select_marks(test_meta):
    marks = set()
    if test_meta.get("smoke") is True:
        marks.add("smoke")
    # Inclusive threshold: exactly 1.0 second is already "slow".
    if test_meta.get("duration_s", 0) >= 1.0:
        marks.add("slow")
    if test_meta.get("layer") == "integration":
        marks.add("integration")
    for name in test_meta.get("extra", []):
        marks.add(name)
    # A set dedupes; sorted() makes the output order part of the contract.
    return sorted(marks)

tests.content:
from solution import select_marks


def test_no_rules_gives_empty_list():
    assert select_marks({}) == []


def test_smoke_only_when_true():
    assert select_marks({"smoke": True}) == ["smoke"]
    # Edge: a falsy/absent smoke value must NOT add the mark.
    assert select_marks({"smoke": False}) == []


def test_slow_threshold_is_inclusive():
    # Boundary: exactly 1.0 second counts as slow.
    assert select_marks({"duration_s": 1.0}) == ["slow"]
    assert select_marks({"duration_s": 0.99}) == []


def test_integration_layer():
    assert select_marks({"layer": "integration"}) == ["integration"]
    assert select_marks({"layer": "unit"}) == []


def test_result_is_sorted():
    meta = {"smoke": True, "duration_s": 2.0, "layer": "integration"}
    assert select_marks(meta) == ["integration", "slow", "smoke"]


def test_extra_marks_are_merged_and_deduped():
    # Tricky: "smoke" appears both via the rule and via extra; it must not
    # be duplicated, and the output stays sorted.
    meta = {"smoke": True, "extra": ["smoke", "wip", "regression"]}
    assert select_marks(meta) == ["regression", "smoke", "wip"]


def test_returns_a_list_not_a_set():
    # Tricky: the contract is a sorted list, so order is observable and
    # callers can index it. A set would not preserve this.
    result = select_marks({"extra": ["b", "a"]})
    assert result == ["a", "b"]
    assert isinstance(result, list)

