def classify_outcome(case, config):
    # Return one of: ("skip", reason), ("xfail", ticket), ("run", None).
    ...

exercises.solution_code:
def classify_outcome(case, config):
    available = config.get("available", [])
    # 1. Cannot set the test up if a required capability is absent.
    #    Report the first missing one, in declaration order.
    for cap in case.get("needs", []):
        if cap not in available:
            return ("skip", "missing: " + cap)
    # 2. Known, tracked bug -> xfail (still runs, but failure is expected).
    ticket = case.get("broken_ticket")
    if ticket:
        return ("xfail", ticket)
    # 3. Flaky test is skipped unless we explicitly force flaky tests to run.
    if case.get("flaky", False) and not config.get("strict_flaky", False):
        return ("skip", "flaky")
    # 4. Nothing special -> run it.
    return ("run", None)

tests.content:
import sys

import pytest

from solution import classify_outcome

FULL = {"available": ["db", "net"], "strict_flaky": False}


def test_plain_case_runs():
    assert classify_outcome({}, FULL) == ("run", None)


def test_missing_capability_skips_with_first_missing():
    case = {"needs": ["db", "gpu"]}
    assert classify_outcome(case, FULL) == ("skip", "missing: gpu")


def test_first_missing_capability_wins_order():
    # Edge: ordering follows case["needs"], not config order.
    case = {"needs": ["gpu", "tpu"]}
    assert classify_outcome(case, FULL) == ("skip", "missing: gpu")


def test_broken_ticket_becomes_xfail():
    case = {"broken_ticket": "JIRA-42"}
    assert classify_outcome(case, FULL) == ("xfail", "JIRA-42")


def test_missing_capability_beats_broken_ticket():
    # Tricky: a skip for a missing capability takes precedence over xfail --
    # there is no point xfailing a test we cannot even set up.
    case = {"needs": ["gpu"], "broken_ticket": "JIRA-1"}
    assert classify_outcome(case, FULL) == ("skip", "missing: gpu")


def test_flaky_skipped_when_not_strict():
    case = {"flaky": True}
    assert classify_outcome(case, FULL) == ("skip", "flaky")


def test_flaky_runs_when_strict():
    case = {"flaky": True}
    cfg = {"available": [], "strict_flaky": True}
    # No needs, no ticket -> strict_flaky keeps it running.
    assert classify_outcome(case, cfg) == ("run", None)


def test_broken_ticket_beats_flaky():
    # Tricky: xfail (known bug) is reported before the flaky skip.
    case = {"broken_ticket": "BUG-9", "flaky": True}
    assert classify_outcome(case, FULL) == ("xfail", "BUG-9")


def test_no_available_key_means_every_capability_missing():
    # Edge: a config without "available" defaults to no capabilities, so any
    # required capability is missing.
    assert classify_outcome({"needs": ["db"]}, {}) == ("skip", "missing: db")


@pytest.mark.skipif(sys.version_info < (3, 8), reason="needs Python 3.8+")
def test_demonstrates_skipif_mark():
    # A real skipif mark in the suite itself: this test is skipped on old
    # interpreters instead of failing to collect.
    assert classify_outcome({}, FULL)[0] == "run"


@pytest.mark.xfail(reason="documents a not-yet-supported feature", strict=True)
def test_demonstrates_xfail_for_unsupported_feature():
    # A real strict xfail: we have NOT specified a "wip" outcome, so asking for
    # one is expected to fail. strict=True means if it ever starts passing,
    # pytest flags it (XPASS -> failure) so we remember to update the test.
    assert classify_outcome({}, FULL) == ("wip", None)
